# --- SAML XML Parsing and Validation ---

class SAMLResponseParser:
    def __init__(self, saml_response_xml):
        self.root = None
        self.saml_response_xml = saml_response_xml
        self._parse_xml()

    def _parse_xml(self):
        try:
            self.root = ET.fromstring(self.saml_response_xml)
        except ET.ParseError as e:
            logger.error(f"SAML XML Parse Error: {e}")
            raise ValueError("Invalid SAML XML format.")

    def _validate_structure(self):
        if self.root.tag != '{urn:oasis:names:tc:SAML:2.0:protocol}Response':
            raise ValueError("Root element is not a SAML Response.")

        status_element = self.root.find('samlp:Status', SAML_NS)
        if status_element is None:
            raise ValueError("SAML Response missing Status element.")

        status_code_element = status_element.find('samlp:StatusCode', SAML_NS)
        if status_code_element is None:
            raise ValueError("SAML Response Status missing StatusCode element.")

        status_value = status_code_element.get('Value')
        if status_value != 'urn:oasis:names:tc:SAML:2.0:status:Success':
            logger.warning(f"SAML Response Status indicates failure: {status_value}")
            raise ValueError(f"SAML Response indicates failure: {status_value}")

        # Further validation (Issuer, AudienceRestriction, etc.) would go here
        # For simplicity, we'll focus on assertion extraction.

    def get_assertion(self):
        self._validate_structure()
        assertion = self.root.find('saml:Assertion', SAML_NS)
        if assertion is None:
            raise ValueError("SAML Response missing Assertion element.")

        # Basic assertion validation
        issuer_element = assertion.find('saml:Issuer', SAML_NS)
        if issuer_element is None or issuer_element.text != IDP_ENTITY_ID:
            logger.warning(f"SAML Assertion Issuer mismatch. Expected {IDP_ENTITY_ID}, got {issuer_element.text if issuer_element else 'None'}")
            # In a real scenario, this would be a hard failure
            # raise ValueError("SAML Assertion Issuer mismatch.")

        audience_restriction = assertion.find('saml:Conditions/saml:AudienceRestriction/saml:Audience', SAML_NS)
        if audience_restriction is None or audience_restriction.text != SP_ENTITY_ID:
            logger.warning(f"SAML Assertion Audience mismatch. Expected {SP_ENTITY_ID}, got {audience_restriction.text if audience_restriction else 'None'}")
            # raise ValueError("SAML Assertion Audience mismatch.")

        return assertion

    def get_name_id(self, assertion_element):
        subject = assertion_element.find('saml:Subject', SAML_NS)
        if subject is None:
            raise ValueError("SAML Assertion missing Subject element.")

        name_id = subject.find('saml:NameID', SAML_NS)
        if name_id is None:
            raise ValueError("SAML Subject missing NameID element.")
        return name_id.text

    def get_attributes(self, assertion_element):
        attributes = {}
        attribute_statement = assertion_element.find('saml:AttributeStatement', SAML_NS)
        if attribute_statement:
            for attr in attribute_statement.findall('saml:Attribute', SAML_NS):
                name = attr.get('Name')
                if name:
                    value_element = attr.find('saml:AttributeValue', SAML_NS)
                    if value_element is not None and value_element.text is not None:
                        attributes[name] = value_element.text.strip()
        return attributes

# --- Django Views ---

@csrf_exempt
def saml_acs(request):
    if request.method == 'POST':
        saml_response_b64 = request.POST.get('SAMLResponse')
        if not saml_response_b64:
            logger.error("SAMLResponse not found in POST data.")
            return render(request, 'saml_error.html', {'error': 'SAMLResponse missing.'}, status=400)

        try:
            saml_response_decoded = base64.b64decode(saml_response_b64).decode('utf-8')
            logger.debug(f"Decoded SAML Response: {saml_response_decoded}")

            parser = SAMLResponseParser(saml_response_decoded)
            assertion = parser.get_assertion()
            name_id = parser.get_name_id(assertion)
            attributes = parser.get_attributes(assertion)

            logger.info(f"SAML Login: NameID={name_id}, Attributes={attributes}")

            # --- User Provisioning and Session Creation ---
            # In a real application, you might map NameID to a username,
            # and attributes to user profile fields.
            # For simplicity, we'll use NameID as username.

            username = name_id
            email = attributes.get('email', f'{username}@example.com') # Fallback email
            first_name = attributes.get('firstName', '')
            last_name = attributes.get('lastName', '')

            user, created = User.objects.get_or_create(username=username)
            if created:
                user.email = email
                user.first_name = first_name
                user.last_name = last_name
                user.set_unusable_password() # SAML users don't have local passwords
                user.save()
                logger.info(f"New user created: {username}")
            else:
                # Update user attributes if necessary
                if user.email != email:
                    user.email = email
                if user.first_name != first_name:
                    user.first_name = first_name
                if user.last_name != last_name:
                    user.last_name = last_name
                if user.has_changed: # Assuming a method to check if fields changed
                    user.save()
                    logger.info(f"User {username} attributes updated.")

            # Log the user in
            # We don't use Django's `authenticate` for SAML because there's no password.
            # Instead, we directly log in the user object.
            user.backend = 'django.contrib.auth.backends.ModelBackend' # Required for login()
            login(request, user)

            logger.info(f"User {username} successfully logged in via SAML.")
            return redirect(getattr(settings, 'LOGIN_REDIRECT_URL', '/'))

        except ValueError as e:
            logger.error(f"SAML Processing Error: {e}")
            return render(request, 'saml_error.html', {'error': str(e)}, status=400)
        except Exception as e:
            logger.exception("Unexpected error during SAML processing.")
            return render(request, 'saml_error.html', {'error': 'An unexpected error occurred.'}, status=500)
    else:
        return render(request, 'saml_error.html', {'error': 'Only POST requests are allowed to this endpoint.'}, status=405)

